type Session struct {
	UserID     string
	Preferences map[string]string
	Permissions []string
	ExpiresAt  time.Time
}

type SessionManager struct {
	mu        sync.Mutex
	sessions  map[string]*Session
	sessionDir string
}

func NewSessionManager(sessionDir string) *SessionManager {
	return &SessionManager{
		sessions:   make(map[string]*Session),
		sessionDir: sessionDir,
	}
}

func (sm *SessionManager) StartSession(userID string, preferences map[string]string, permissions []string, duration time.Duration) (string, error) {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	sessionID := generateRandomString(32)
	expiration := time.Now().Add(duration)

	newSession := &Session{
		UserID:     userID,
		Preferences: preferences,
		Permissions: permissions,
		ExpiresAt:  expiration,
	}

	sm.sessions[sessionID] = newSession

	if err := sm.saveSession(sessionID); err != nil {
		return "", fmt.Errorf("failed to save session: %w", err)
	}

	return sessionID, nil
}

func (sm *SessionManager) LoadSession(sessionID string) (*Session, error) {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	if sess, exists := sm.sessions[sessionID]; exists {
		if time.Now().After(sess.ExpiresAt) {
			delete(sm.sessions, sessionID)
			return nil, errors.New("session expired")
		}
		return sess, nil
	}

	if err := sm.reloadSession(sessionID); err != nil {
		return nil, fmt.Errorf("failed to reload session: %w", err)
	}

	return sm.sessions[sessionID], nil
}

func (sm *SessionManager) saveSession(sessionID string) error {
	sessionPath := fmt.Sprintf("%s/%s", sm.sessionDir, sessionID)
	file, err := os.Create(sessionPath)
	if err != nil {
		return err
	}
	defer file.Close()

	enc := gob.NewEncoder(file)
	return enc.Encode(sm.sessions[sessionID])
}

func (sm *SessionManager) reloadSession(sessionID string) error {
	sessionPath := fmt.Sprintf("%s/%s", sm.sessionDir, sessionID)
	file, err := os.Open(sessionPath)
	if err != nil {
		return err
	}
	defer file.Close()

	var sess Session
	dec := gob.NewDecoder(file)
	if err := dec.Decode(&sess); err != nil {
		return err
	}

	sm.sessions[sessionID] = &sess
	return nil
}

func generateRandomString(n int) string {
	const letters = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	result := make([]byte, n)
	for i := range result {
		result[i] = letters[rand.Intn(len(letters))]
	}
	return string(result)
}

